import collections

class Solution:
    def groupStrings(self, strings: list[str]) -> list[list[str]]:
        groups = collections.defaultdict(list)

        for s in strings:
            if not s:
                groups[""].append(s)
                continue

            shift = ord(s[0]) - ord('a')
            key_chars = []
            for char in s:
                # Calculate the character's new position after shifting the first char to 'a'
                # (ord(char) - shift - ord('a')) gives the 0-25 index relative to 'a'
                # Adding 26 and taking modulo 26 handles negative results (wrap-around from 'a' to 'z')
                normalized_idx = (ord(char) - shift - ord('a') + 26) % 26
                key_chars.append(chr(ord('a') + normalized_idx))

            key_string = "".join(key_chars)
            groups[key_string].append(s)

        return list(groups.values())
